const input = $input.first().json;

const infra_id = `infra_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
const timestamp = new Date().toISOString();

let severity = 'low';
if (input.trigger_type === 'incident' || input.trigger_type === 'security_audit') {
  severity = 'high';
} else if (input.trigger_type === 'scaling_event') {
  severity = 'medium';
}

// WF-9 operates in pure observer mode - no authority to enforce or block
return {
  json: {
    ...input,
    infra_id,
    timestamp,
    severity,
    observer_mode: true,
    wf9_role: 'observer_only'
  }
};

// Observer only - reports status, does not decide autoscale
const config = $('Workflow Configuration').first().json;
const cpu_usage = Math.random() * 100;
const memory_usage = Math.random() * 100;
const latency = Math.random() * 1000;
const uptime = 99.5 + Math.random() * 0.5;

let infra_status = 'healthy';

if (cpu_usage > config.cpu_threshold || memory_usage > config.memory_threshold) {
  infra_status = 'degraded';
}

if (latency > config.latency_threshold_ms || uptime < 99.5) {
  infra_status = 'critical';
}

return {
  json: {
    check_type: 'infrastructure_health',
    infra_status,
    metrics: {
      cpu_usage: cpu_usage.toFixed(2),
      memory_usage: memory_usage.toFixed(2),
      latency_ms: latency.toFixed(2),
      uptime_percent: uptime.toFixed(3)
    }
  }
};

const service_availability = Math.random() > 0.05;
const workflow_failures = Math.floor(Math.random() * 10);
const corrupted_states = Math.random() > 0.95 ? ['workflow_state_123'] : [];
const integrity_ok = service_availability && workflow_failures < 5 && corrupted_states.length === 0;

return {
  json: {
    check_type: 'system_integrity',
    integrity_ok,
    failed_components: corrupted_states,
    metrics: {
      service_availability,
      workflow_failures,
      corrupted_states_count: corrupted_states.length
    }
  }
};

const config = $('Workflow Configuration').first().json;
const vulnerability_count = Math.floor(Math.random() * 5);
const intrusion_attempts = Math.floor(Math.random() * 20);
const key_misuse_detected = Math.random() > 0.98;
const abnormal_traffic = Math.random() > 0.9;

let security_risk = 'low';
const threats = [];

if (vulnerability_count > 2 || key_misuse_detected) {
  security_risk = 'high';
  threats.push('Critical vulnerabilities detected');
} else if (intrusion_attempts > 10 || abnormal_traffic) {
  security_risk = 'medium';
  threats.push('Elevated intrusion attempts');
}

return {
  json: {
    check_type: 'cybersecurity',
    security_risk,
    threats,
    metrics: {
      vulnerability_count,
      intrusion_attempts,
      key_misuse_detected,
      abnormal_traffic
    }
  }
};

const config = $('Workflow Configuration').first().json;
const data_retention_ok = Math.random() > 0.1;
const encryption_ok = Math.random() > 0.05;
const access_policies_ok = Math.random() > 0.1;
const regulatory_alignment_ok = Math.random() > 0.15;
const violations = [];
if (!data_retention_ok) violations.push('Data retention policy violation');
if (!encryption_ok) violations.push('Encryption standards not met');
if (!access_policies_ok) violations.push('Access policy gaps detected');
if (!regulatory_alignment_ok) violations.push('Regulatory alignment issues');
const compliance_ok = violations.length === 0;
return {
  json: {
    check_type: 'it_compliance',
    compliance_ok,
    violations,
    frameworks_checked: config.compliance_frameworks.split(',')
  }
};

// Observer only - reports access issues, does not decide lockdown
const privileged_access_violations = Math.floor(Math.random() * 3);
const token_misuse = Math.random() > 0.95;
const role_boundary_breaches = Math.floor(Math.random() * 2);

const access_issues = [];
if (privileged_access_violations > 0) access_issues.push(`${privileged_access_violations} privileged access violations`);
if (token_misuse) access_issues.push('Token misuse detected');
if (role_boundary_breaches > 0) access_issues.push(`${role_boundary_breaches} role boundary breaches`);

return {
  json: {
    check_type: 'access_control',
    access_issues,
    metrics: {
      privileged_access_violations,
      token_misuse,
      role_boundary_breaches
    }
  }
};

const pipeline_failures = Math.floor(Math.random() * 5);
const etl_errors = Math.floor(Math.random() * 10);
const stale_sources = Math.random() > 0.85 ? ['data_source_A', 'data_source_B'] : [];
const pipelines_ok = pipeline_failures === 0 && etl_errors < 5 && stale_sources.length === 0;

return {
  json: {
    check_type: 'data_engineering',
    pipelines_ok,
    stale_sources,
    metrics: {
      pipeline_failures,
      etl_errors,
      stale_sources_count: stale_sources.length
    }
  }
};

// Observer only - reports graph health, does not decide repairs
const graph_consistency_score = 0.85 + Math.random() * 0.15;
const embedding_drift = Math.random() * 0.3;
const broken_relationships = Math.floor(Math.random() * 10);

let graph_health = 'ok';

if (graph_consistency_score < 0.9 || embedding_drift > 0.2 || broken_relationships > 5) {
  graph_health = 'degraded';
}

return {
  json: {
    check_type: 'knowledge_graph',
    graph_health,
    metrics: {
      graph_consistency_score: graph_consistency_score.toFixed(3),
      embedding_drift: embedding_drift.toFixed(3),
      broken_relationships
    }
  }
};

const total_workflows = 50 + Math.floor(Math.random() * 50);
const active_workflows = Math.floor(total_workflows * (0.6 + Math.random() * 0.3));
const total_executions = 1000 + Math.floor(Math.random() * 5000);
const failed_executions = Math.floor(total_executions * (0.01 + Math.random() * 0.05));
const avg_execution_time_ms = 500 + Math.random() * 2000;
const cost_usd = 100 + Math.random() * 900;

return {
  json: {
    check_type: 'data_analytics',
    kpis: {
      total_workflows,
      active_workflows,
      total_executions,
      failed_executions,
      success_rate: ((total_executions - failed_executions) / total_executions * 100).toFixed(2),
      avg_execution_time_ms: avg_execution_time_ms.toFixed(2),
      estimated_monthly_cost_usd: cost_usd.toFixed(2)
    }
  }
};

const config = $('Workflow Configuration').first().json;
const last_backup_hours_ago = Math.floor(Math.random() * 48);
const backup_completed = last_backup_hours_ago < 24;
const restore_points_valid = Math.random() > 0.1;
const backup_status = backup_completed && restore_points_valid ? 'ok' : 'failed';
const last_backup = new Date(Date.now() - last_backup_hours_ago * 3600000).toISOString();

return {
  json: {
    check_type: 'backup_operations',
    backup_status,
    last_backup,
    metrics: {
      last_backup_hours_ago,
      restore_points_valid,
      retention_days: config.backup_retention_days
    }
  }
};

// Build WF-9 signal payload for WF-10
const observerSignal = $json;
const inputData = $('Input Normalization & Trace Tagging').first().json;
const configData = $('Workflow Configuration').first().json;

// WF-9 standardized signal format for WF-10
const wf9Signal = {
  source_workflow: 'WF-9',
  signal_type: 'infrastructure_observation',
  request_id: inputData.infra_id || `req_${Date.now()}`,
  timestamp: new Date().toISOString(),

  // Observer assessment (advisory only)
  alert_type: observerSignal.alert_type,
  severity: observerSignal.severity,
  confidence: observerSignal.confidence,
  recommended_action: observerSignal.recommended_action,
  reasoning: observerSignal.reasoning,

  // Metrics and telemetry
  metrics: observerSignal.metrics || {},
  observed_issues: observerSignal.observed_issues || [],

  // Routing flags (WF-10 decides actual routing)
  requires_wf10_review: observerSignal.requires_wf10_review || false,
  requires_crea_review: observerSignal.requires_crea_review || false,

  // Input context
  input_context: {
    trigger_type: inputData.trigger_type,
    scope: inputData.scope,
    severity: inputData.severity,
    infra_id: inputData.infra_id
  },

  // Configuration snapshot
  config_snapshot: {
    cpu_threshold: configData.cpu_threshold,
    memory_threshold: configData.memory_threshold,
    latency_threshold_ms: configData.latency_threshold_ms,
    compliance_frameworks: configData.compliance_frameworks
  },

  // Metadata
  workflow_id: $workflow.id,
  workflow_name: $workflow.name,
  execution_id: $execution.id,

  // WF-9 role declaration
  observer_note: 'WF-9 observes and reports only. WF-10 decides all actions.'
};

return {
  json: wf9Signal
};

// Combine CTO (technology) + CIO (infrastructure) orchestrator decisions
const sev={low:1,medium:2,high:3};
const cto=$('CTO Orchestrator Agent').first().json||{};
const cio=$('CIO Orchestrator Agent').first().json||{};
const pick=(a,b)=>((sev[a]||0)>=(sev[b]||0)?a:b);
const severity=pick(cto.severity,cio.severity)||'low';
const issues=[].concat(cto.observed_issues||[],cio.observed_issues||[]);
const order=['none','investigate','throttle','autoscale','pause','lockdown'];
const action=(order.indexOf(cto.recommended_action)>=order.indexOf(cio.recommended_action))?cto.recommended_action:cio.recommended_action;
return [{ json: {
  source_workflow:'WF-9', department:'tech_infra',
  cto_decision:cto, cio_decision:cio,
  severity:severity, recommended_action:action||'none',
  observed_issues:issues,
  requires_wf10_review:(cto.requires_wf10_review||cio.requires_wf10_review||false),
  requires_crea_review:(cto.requires_crea_review||cio.requires_crea_review||false),
  confidence:Math.min(cto.confidence??0.9, cio.confidence??0.9),
  reasoning:'CTO: '+(cto.reasoning||'')+' | CIO: '+(cio.reasoning||'')
}}];
